class Solution:
    def removeDuplicates(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        k = 0

        for num in nums:
            # Keep if less than 2 occurrences
            if k < 2 or num != nums[k-2]:
                nums[k] = num
                k += 1

        return k
